{"code": "import json, re

# Load books data with publication years
try:
    books_file = locals()['var_functions.query_db:20']
    with open(books_file, 'r') as f:
        books = json.load(f)

    # Process through data
    year_pattern = re.compile(r'(\d{4})')
    for book in books:
        year = int(book['publication_year'])
        book['decade'] = (year // 10) * 10
        book['decade_label'] = str(book['decade']) + 's'

    print('__RESULT__:')
    print(json.dumps({
        'count': len(books),
        'sample_decades': sorted(list(set(b['decade_label'] for b in books)))[:10]
    }))
except Exception as e:
    print('__RESULT__:')
    print(json.dumps({'error': str(e)}))"}

